const TicTacToe = (function () {
  'use strict';

  const EMPTY = '';
  const PLAYER_X = 'X';
  const PLAYER_O = 'O';
  const BOARD_SIZE = 3;
  const TOTAL_CELLS = BOARD_SIZE * BOARD_SIZE;

  // 승리 조건: 행, 열, 대각선
  const WIN_LINES = [
    [0, 1, 2], [3, 4, 5], [6, 7, 8], // 행
    [0, 3, 6], [1, 4, 7], [2, 5, 8], // 열
    [0, 4, 8], [2, 4, 6],            // 대각선
  ];

  function createGame() {
    let board = Array(TOTAL_CELLS).fill(EMPTY);
    let currentPlayer = PLAYER_X;
    let gameOver = false;
    let winningLine = null;

    function getBoard() {
      return [...board];
    }

    function getCurrentPlayer() {
      return currentPlayer;
    }

    function isGameOver() {
      return gameOver;
    }

    function getWinningLine() {
      return winningLine ? [...winningLine] : null;
    }

    // 승리 여부 확인
    function checkWinner() {
      for (const line of WIN_LINES) {
        const [a, b, c] = line;
        if (board[a] !== EMPTY && board[a] === board[b] && board[b] === board[c]) {
          return { winner: board[a], line };
        }
      }
      return null;
    }

    // 무승부 확인
    function isDraw() {
      return !gameOver && board.every(cell => cell !== EMPTY) && checkWinner() === null;
    }

    // 셀에 마크 놓기
    function makeMove(index) {
      if (index < 0 || index >= TOTAL_CELLS) {
        return { success: false, reason: '유효하지 않은 위치입니다' };
      }
      if (board[index] !== EMPTY) {
        return { success: false, reason: '이미 선택된 칸입니다' };
      }
      if (gameOver) {
        return { success: false, reason: '게임이 이미 종료되었습니다' };
      }

      board[index] = currentPlayer;

      const result = checkWinner();
      if (result) {
        gameOver = true;
        winningLine = result.line;
        return { success: true, winner: result.winner, line: result.line };
      }

      if (isDraw()) {
        gameOver = true;
        return { success: true, draw: true };
      }

      currentPlayer = currentPlayer === PLAYER_X ? PLAYER_O : PLAYER_X;
      return { success: true };
    }

    // 게임 초기화
    function reset() {
      board = Array(TOTAL_CELLS).fill(EMPTY);
      currentPlayer = PLAYER_X;
      gameOver = false;
      winningLine = null;
    }

    return {
      getBoard,
      getCurrentPlayer,
      isGameOver,
      getWinningLine,
      checkWinner,
      isDraw,
      makeMove,
      reset,
      EMPTY,
      PLAYER_X,
      PLAYER_O,
    };
  }

  return { createGame, WIN_LINES, EMPTY, PLAYER_X, PLAYER_O, BOARD_SIZE, TOTAL_CELLS };
})();

